.overlay {
  position: fixed; top: 0; left: 0; right: 0; bottom: 0;
  background: rgba(10,10,18,0.85);
  display: flex; align-items: center; justify-content: center;
  z-index: 100;
}
.modal {
  background: var(--bg-panel);
  border: 1px solid var(--border-bright);
