  border-bottom: none;
  border-radius: 6px 6px 0 0;
  background: var(--bg-dark);
  color: var(--text-dim);
  cursor: pointer;
  font-size: 13px;
}
.tab.active { background: var(--bg-panel); color: var(--text-bright); border-color: var(--border-bright); }

/* Affinity display */
.affinity-row {
  display: flex; align-items: center; gap: 8px;
