.affinity-icon { width: 24px; text-align: center; }
.affinity-bar { flex: 1; }
.affinity-level { font-size: 12px; color: var(--text-dim); min-width: 60px; text-align: right; }
.affinity-milestone { font-size: 10px; color: var(--accent-gold); }

/* Element colors */
.elem-fire { color: var(--accent-fire); }
.elem-ice { color: var(--accent-ice); }
.elem-nature { color: var(--accent-nature); }
.elem-shadow { color: var(--accent-shadow); }
.elem-arcane { color: var(--accent-arcane); }
.elem-physical { color: var(--stamina-bar); }

