      spellSlots.appendChild(el('div', {
        className: `loadout-slot ${spell ? 'filled' : ''}`,
        onclick: () => {
          if (spell) {
            p.spellLoadout[i] = null;
            saveGame();
            renderLoadout();
          }
        },
      },
        spell ? el('span', { style: { fontSize: '9px', textAlign: 'center' } },
          icon(spell.icon, 'icon-sm'), el('br', {}), spell.name) :
