.btn-large { padding: 12px 28px; font-size: 18px; }
.btn-small { padding: 4px 8px; font-size: 12px; }
.btn-dialogue { display: block; width: 100%; text-align: left; margin: 4px 0; padding: 10px 14px; }
.btn-dialogue:hover { background: #2d2d50; border-color: var(--gold); }
.btn.disabled, .btn-disabled { opacity: 0.4; pointer-events: none; }

