  setStatusFilter: (status: "all" | ReviewState) => void;
  setHypothesisFilter: (hypothesis: string | null) => void;
  setSearchQuery: (query: string) => void;
  setSelectedRunKey: (key: string | null) => void;
  clearAll: () => void;
}

const INITIAL: FilterState = {
  roundFilter: null,
  domainFilter: null,
  statusFilter: "all",
